import{_ as r,o as t,c as l,ae as e}from"./chunks/framework.BzQXgbNp.js";const a="/assets/dash-1.CnDNqcEq.png",u=JSON.parse('{"title":"🖥️ 網頁版首頁與帳號登入","description":"","frontmatter":{},"headers":[],"relativePath":"Web-Dashboard.md","filePath":"Web-Dashboard.md"}'),s={name:"Web-Dashboard.md"};function i(n,o,d,c,g,h){return t(),l("div",null,[...o[0]||(o[0]=[e('<h1 id="🖥️-網頁版首頁與帳號登入" tabindex="-1">🖥️ 網頁版首頁與帳號登入 <a class="header-anchor" href="#🖥️-網頁版首頁與帳號登入" aria-label="Permalink to &quot;🖥️ 網頁版首頁與帳號登入&quot;">​</a></h1><p>本伺服器提供全功能網頁儀表板，支援跨平台即時查詢伺服器經濟、個人數據與遊戲即時狀態。</p><p><img src="'+a+'" alt="網頁儀表板首頁"></p><hr><h2 id="🔑-1-帳號登入與綁定" tabindex="-1">🔑 1. 帳號登入與綁定 <a class="header-anchor" href="#🔑-1-帳號登入與綁定" aria-label="Permalink to &quot;🔑 1. 帳號登入與綁定&quot;">​</a></h2><p>為了保障您的虛擬資產安全，系統已啟用 Discord 安全綁定機制：</p><ol><li>點選網頁右上角的 <strong><code>[ 以 Discord 帳號登入 ]</code></strong> 按鈕。</li><li>授權登入後，系統會自動尋找您在遊戲內綁定的 Minecraft 角色。</li><li><strong>未綁定提示</strong>：若您的帳號尚未綁定，請先登入遊戲內，輸入 <code>/discord link</code> 獲取一組 6 位數驗證碼，並至官方 Discord 頻道進行綁定。</li></ol><hr><h2 id="🏠-2-首頁核心看板" tabindex="-1">🏠 2. 首頁核心看板 <a class="header-anchor" href="#🏠-2-首頁核心看板" aria-label="Permalink to &quot;🏠 2. 首頁核心看板&quot;">​</a></h2><p>登入網頁首頁後，您可以直觀查閱以下即時數據：</p><ul><li><strong>💰 全服流通金幣</strong>：目前伺服器中所有玩家持有的金幣總額。</li><li><strong>🏛️ 累計收繳稅額</strong>：顯示商店交易已被系統回收並銷毀 the 5% 印花稅金幣總量。</li><li><strong>🏪 營運中箱子商店</strong>：當前全伺服器正在營業的玩家商店總數量。</li><li><strong>🟢 遊戲即時狀態</strong>： <ul><li><strong>線上燈號</strong>：即時顯示您目前在遊戲中是「線上」或「離線」。</li><li><strong>遊戲內座標</strong>：您在線時，即時同步顯示您的三維世界座標 (X, Y, Z)。</li><li><strong>遊戲內餘額</strong>：即時與遊戲內同步您的金幣總值。</li><li><strong>伺服器 TPS</strong>：實時反映伺服器的運作效率（滿分 20.00）。</li></ul></li><li><strong>🏆 富豪排行榜</strong>：顯示全服金幣餘額前 10 名的玩家排行榜，並載入其皮膚頭像。</li><li><strong>🛒 即時交易動態</strong>：免重新整理，即時推播全服最新的商店成交紀錄。</li></ul><hr><h2 id="🤖-3-假人控制面板-fake-player-control" tabindex="-1">🤖 3. 假人控制面板 (Fake Player Control) <a class="header-anchor" href="#🤖-3-假人控制面板-fake-player-control" aria-label="Permalink to &quot;🤖 3. 假人控制面板 (Fake Player Control)&quot;">​</a></h2><ul><li>點選側邊欄的 <strong><code>[ 假人控制 ]</code></strong> 可進入本分頁（需登入）。</li><li><strong>召喚與召回</strong>：在上方輸入名稱（系統會自動帶上 <code>fp_</code> 前綴），點擊即可一鍵將假人召喚上線或下線（召喚時，您本人必須在遊戲內線上）。</li><li><strong>動作指令</strong>：包含連續攻擊 (Attack)、右鍵使用 (Use)、跳躍 (Jump)、蹲下 (Sneak)、疾跑 (Sprint) 以及丟棄物品等，均可直接在網頁端點選進行遙控，無須手動記憶或輸入命令。</li></ul><hr><h2 id="🧭-4-傳送點與家園管理-teleport-homes" tabindex="-1">🧭 4. 傳送點與家園管理 (Teleport &amp; Homes) <a class="header-anchor" href="#🧭-4-傳送點與家園管理-teleport-homes" aria-label="Permalink to &quot;🧭 4. 傳送點與家園管理 (Teleport &amp; Homes)&quot;">​</a></h2><ul><li>點選側邊欄的 <strong><code>[ 傳送點管理 ]</code></strong> 可進入本分頁（需登入）。</li><li><strong>🏠 我的家園 (Homes)</strong>： <ul><li>列出您名下的所有家園儲存點、座標、世界維度。</li><li>可以直接在網頁上點擊 <strong><code>[ 刪除家園 ]</code></strong> 並彈出二次確認對話框進行安全刪除。</li></ul></li><li><strong>🏁 公共地標 (Warps)</strong>： <ul><li>列出伺服器現有的全部公共地標、座標與維度。</li><li>若您是管理員 (Admin)，可以直接在網頁上點選 <strong><code>[ 刪除地標 ]</code></strong>（需二次確認）。非管理員則僅能檢視，無法進行修改。</li></ul></li></ul>',17)])])}const m=r(s,[["render",i]]);export{u as __pageData,m as default};
